import{c as a,Q as i,j as t,m as n}from"./chunks/framework.Bhbi9jCp.js";const g=JSON.parse('{"title":"IO 五种模型","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/20-IO五种模型.md","filePath":"osLearning/20-IO五种模型.md","lastUpdated":1781095972000}'),p={name:"osLearning/20-IO五种模型.md"};function l(e,s,h,o,d,r){return i(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="io-五种模型" tabindex="-1">IO 五种模型 <a class="header-anchor" href="#io-五种模型" aria-label="Permalink to &quot;IO 五种模型&quot;">​</a></h1><p>&quot;同步、异步、阻塞、非阻塞&quot;这四个词,大概是后端圈被用得最乱的四个词。有人说&quot;epoll 是异步 IO&quot;(不是),有人说&quot;async/await 所以底层是异步 IO&quot;(不一定),有人说&quot;非阻塞就是异步&quot;(完全两码事)。词一乱,你读 Nginx、Node、Redis、Go netpoller 的任何资料都像在看加密通信。其实这五种模型回答的是同一个朴素问题:<strong><code>read</code> 的时候数据还没到,线程怎么办?</strong>——把这一个问题想清楚,四个词自动归位。</p><blockquote><p>一句话先记住:<strong>阻塞/非阻塞说的是&quot;调用会不会卡住线程&quot;,同步/异步说的是&quot;数据拷贝由谁完成&quot;</strong>。epoll 是同步 IO 多路复用——它只告诉你 fd 就绪了,真正的 read/write 还得你自己做;io_uring 才接近真异步——你提交操作,内核连等带拷全包,完成后给你结果。高性能网络的主流答案是:<strong>非阻塞 fd + IO 多路复用 + 事件循环</strong>,不是&quot;一个连接一个线程&quot;。</p></blockquote><hr><h2 id="一、一次-io-的两个阶段" tabindex="-1">一、一次 IO 的两个阶段 <a class="header-anchor" href="#一、一次-io-的两个阶段" aria-label="Permalink to &quot;一、一次 IO 的两个阶段&quot;">​</a></h2><p>所有模型的差别,都藏在这张图里。以 socket read 为例:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>            阶段 1                          阶段 2</span></span>
<span class="line"><span>   ┌──────────────────────┐    ┌──────────────────────────┐</span></span>
<span class="line"><span>   │ 等数据到达内核缓冲区     │    │ 把数据从内核缓冲区          │</span></span>
<span class="line"><span>   │ (网络包还在路上,        │ →  │ 拷贝到你的用户态 buffer     │</span></span>
<span class="line"><span>   │  谁知道要等多久)        │    │ (这一步是确定的 CPU 工作)  │</span></span>
<span class="line"><span>   └──────────────────────┘    └──────────────────────────┘</span></span></code></pre></div><p>阶段 1 是不确定的等待——对端可能一秒后发数据,可能永远不发;阶段 2 是确定的搬运工作。<strong>五种 IO 模型,本质就是对&quot;这两个阶段分别由谁负责、用什么方式等&quot;的五种排列组合</strong>。带着这个框架往下看,每种模型一句话就能说清。</p><hr><h2 id="二、阻塞-io-最老实的等法" tabindex="-1">二、阻塞 IO:最老实的等法 <a class="header-anchor" href="#二、阻塞-io-最老实的等法" aria-label="Permalink to &quot;二、阻塞 IO:最老实的等法&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 没数据?那我睡了</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你的线程: read ──→ [睡眠 zzz...........] ──→ 拷贝数据 ──→ 返回</span></span>
<span class="line"><span>                   ↑                    ↑</span></span>
<span class="line"><span>                   内核:没数据,挂起你    数据到了,中断唤醒你</span></span></code></pre></div><p>线程在阶段 1 直接睡掉,数据到了被内核唤醒,自己做阶段 2。注意一个常见误解:<strong>阻塞期间线程不占 CPU</strong>——它在睡眠队列里,调度器根本不看它。阻塞的代价不是烧 CPU,是<strong>这个线程在等待期间什么别的都干不了</strong>。</p><p>所以它的优缺点都很直白:</p><ul><li>优点:<strong>编程模型最简单</strong>,代码就是顺序逻辑,适合脚本和少量连接</li><li>缺点:一个连接独占一个线程/进程;一万个连接就是一万个线程,每个线程几 MB 栈内存,加上上下文切换开销,<strong>这就是经典的 C10K 问题</strong>——机器没干活,光养线程就趴了</li></ul><hr><h2 id="三、非阻塞-io-我不等-我再来" tabindex="-1">三、非阻塞 IO:我不等,我再来 <a class="header-anchor" href="#三、非阻塞-io-我不等-我再来" aria-label="Permalink to &quot;三、非阻塞 IO:我不等,我再来&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETFL, O_NONBLOCK);</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4096</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> errno </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EAGAIN) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 没数据——这不是错误!是&quot;暂时没有,回头再来&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>设了 <code>O_NONBLOCK</code> 之后,阶段 1 不等了:没数据立刻返回 <code>EAGAIN</code>。第一个要扭过来的认知是:<strong>EAGAIN 不是 error,是一种正常状态</strong>,新手把它当错误处理、直接断开连接,是非阻塞编程的第一跤。</p><p>但光有非阻塞还不够。如果你自己轮询:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, n) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> errno </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">==</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EAGAIN) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 空转,CPU 100%,比阻塞还糟</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>线程是不卡了,CPU 被烧光了——<strong>非阻塞解决了&quot;卡住&quot;,制造了&quot;该什么时候再来问&quot;</strong>。这个问题它自己答不了,要交给下一个模型。所以非阻塞 IO 几乎从不单独使用,它的真实身份是<strong>事件循环的地基</strong>:fd 先全部设成非阻塞,&quot;什么时候该读&quot;则交给多路复用器。</p><hr><h2 id="四、io-多路复用-一个线程替一万个-fd-等" tabindex="-1">四、IO 多路复用:一个线程替一万个 fd 等 <a class="header-anchor" href="#四、io-多路复用-一个线程替一万个-fd-等" aria-label="Permalink to &quot;四、IO 多路复用:一个线程替一万个 fd 等&quot;">​</a></h2><p>多路复用(multiplexing)的思路:既然每个 fd 单独等太浪费,<strong>那就把一万个 fd 的&quot;等&quot;合并成一次系统调用</strong>,谁有动静叫醒我,我再去处理谁。</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> n </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> epoll_wait</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(epfd, events, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">64</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 一觉睡到任意 fd 就绪</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">; i </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> n; i</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">++</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // 就绪的 fd 自己去 read/write(阶段 2 还是你做)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>       fd1  fd2  fd3 ... fd10000</span></span>
<span class="line"><span>        │    │    │         │</span></span>
<span class="line"><span>        └────┴────┴────┬────┘</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                 epoll_wait(睡)</span></span>
<span class="line"><span>                       │  ← 任意 fd 就绪,唤醒</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>              对就绪 fd 逐个 read/write</span></span></code></pre></div><p>select / poll / epoll 是同一模型的三代实现,差别在&quot;内核怎么知道你关心哪些 fd&quot;:</p><table tabindex="0"><thead><tr><th>API</th><th>机制</th><th>问题</th></tr></thead><tbody><tr><td>select</td><td>每次调用传全量 fd 集合,内核线性扫描</td><td><strong>fd 上限 1024</strong>,每次全量拷贝 + 两边各扫一遍</td></tr><tr><td>poll</td><td>同 select,换了数据结构</td><td>没有 1024 限制了,但还是全量拷贝全量扫</td></tr><tr><td>epoll</td><td><strong>内核常驻保存关注集合,只返回就绪的 fd</strong></td><td>基本没有,所以它赢了</td></tr></tbody></table><p>一万连接里只有 1% 活跃时,select/poll 每次要扫一万个,epoll 只返回那 100 个——<strong>这就是 epoll 快的全部原因:省掉了无效扫描,不是 read 本身变快了</strong>(内部机制详见 21 篇)。</p><p><strong>划重点:epoll 不是异步 IO</strong>。它把阶段 1 的&quot;等&quot;做到了极致高效,但只通知你&quot;可以读了&quot;,阶段 2 的拷贝仍然发生在你调用 read 的那一刻、由你的线程完成。按定义,这是<strong>同步 IO</strong>。Nginx、Redis、Node 的底座全是它。</p><hr><h2 id="五、信号驱动-io-理论很美-工程弃疗" tabindex="-1">五、信号驱动 IO:理论很美,工程弃疗 <a class="header-anchor" href="#五、信号驱动-io-理论很美-工程弃疗" aria-label="Permalink to &quot;五、信号驱动 IO:理论很美,工程弃疗&quot;">​</a></h2><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETOWN, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getpid</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">());</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fcntl</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, F_SETFL, O_ASYNC </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> O_NONBLOCK);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 数据就绪时,内核给你发 SIGIO 信号</span></span></code></pre></div><p>思路是把阶段 1 的通知改成信号:线程该干嘛干嘛,数据到了内核发 <code>SIGIO</code>,你在信号处理函数里去读。听起来比 epoll 还潇洒,实际工程上几乎没人用,原因全在信号本身:</p><ul><li>信号处理函数里能安全调用的函数极少(异步信号安全问题,详见 24 篇)</li><li>多个 fd 就绪时,SIGIO 不告诉你是哪个 fd,你还得自己查</li><li>信号可能合并、可能丢,语义又复杂又脆</li></ul><p>现代 Linux 的态度很明确:<strong>真想把信号纳入事件体系,用 signalfd 把信号变成 fd 塞进 epoll</strong>(18 篇讲过)——让信号迁就事件循环,而不是让网络模型迁就信号。这个模型你需要认识它(五种模型凑数少不了它),但不需要用它。</p><hr><h2 id="六、异步-io-连拷贝都不用你管" tabindex="-1">六、异步 IO:连拷贝都不用你管 <a class="header-anchor" href="#六、异步-io-连拷贝都不用你管" aria-label="Permalink to &quot;六、异步 IO:连拷贝都不用你管&quot;">​</a></h2><p>前四种模型,阶段 2 全是调用线程自己做。真正的异步 IO(asynchronous IO)把两个阶段全部外包:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你:提交一个 read 请求(带上我的 buffer)</span></span>
<span class="line"><span>内核:等数据 + 拷贝到你的 buffer,全程不打扰你</span></span>
<span class="line"><span>内核:完成了,通知你</span></span>
<span class="line"><span>你:直接拿结果用,数据已经躺在 buffer 里了</span></span></code></pre></div><p>注意差别:epoll 通知你&quot;<strong>可以读了</strong>&quot;(你还要自己读),异步 IO 通知你&quot;<strong>已经读完了</strong>&quot;(结果就在那)。</p><p>Linux 在这条路上憋屈了很多年:POSIX AIO 实际是 glibc 用线程池模拟的,普通文件支持有限,socket 基本没法用,被嫌弃了二十年。真正翻盘的是 Linux 5.1 引入的 <strong>io_uring</strong>:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_prep_read</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(sqe, fd, buf, len, offset);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // 把请求写进提交队列</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_submit</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          // 提交(可以攒一批一起交)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">io_uring_wait_cqe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">ring</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">cqe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                  // 从完成队列收结果</span></span></code></pre></div><p>io_uring 用两个用户态与内核共享的环形队列(提交队列 SQ / 完成队列 CQ)传递请求和结果,把 read、write、accept、send、timeout、甚至文件 IO <strong>全部统一成&quot;提交 → 完成&quot;模型</strong>,批量提交还能省系统调用。它是 Linux 第一个&quot;文件和网络都好使&quot;的异步 IO,细节留给 22 篇。</p><hr><h2 id="七、五种模型同框-一张时序图收尾" tabindex="-1">七、五种模型同框:一张时序图收尾 <a class="header-anchor" href="#七、五种模型同框-一张时序图收尾" aria-label="Permalink to &quot;七、五种模型同框:一张时序图收尾&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                 阶段1(等数据)              阶段2(拷贝)</span></span>
<span class="line"><span>阻塞 IO        ████████ 线程睡在 read 里 ████ │ ██ 线程拷贝 │</span></span>
<span class="line"><span>非阻塞 IO      ↻ 反复 read 得 EAGAIN(烧CPU)  │ ██ 线程拷贝 │</span></span>
<span class="line"><span>IO 多路复用    ████ 线程睡在 epoll_wait ████   │ ██ 线程拷贝 │ ← 但它替一万个 fd 一起等</span></span>
<span class="line"><span>信号驱动       线程干别的…(SIGIO!)            │ ██ 线程拷贝 │</span></span>
<span class="line"><span>异步 IO        线程干别的………………………………(完成通知!结果已就位)</span></span>
<span class="line"><span>                                              ↑ 拷贝是内核做的</span></span></code></pre></div><table tabindex="0"><thead><tr><th>模型</th><th>阶段 1 谁等</th><th>阶段 2 谁拷</th><th>分类</th><th>典型 API</th></tr></thead><tbody><tr><td>阻塞 IO</td><td>线程睡在调用里</td><td>调用线程</td><td>同步阻塞</td><td>默认 read</td></tr><tr><td>非阻塞 IO</td><td>线程反复来问</td><td>调用线程</td><td>同步非阻塞</td><td>O_NONBLOCK + read</td></tr><tr><td>IO 多路复用</td><td>线程睡在 epoll_wait</td><td>调用线程</td><td><strong>同步</strong>非阻塞</td><td>epoll + read</td></tr><tr><td>信号驱动</td><td>内核发信号通知</td><td>调用线程</td><td>同步</td><td>SIGIO</td></tr><tr><td>异步 IO</td><td>内核</td><td><strong>内核</strong></td><td>异步</td><td>io_uring / AIO</td></tr></tbody></table><p>看清表里那一列:<strong>前四种的拷贝都是你做的,所以都是同步 IO;只有最后一种是异步</strong>。&quot;同步/异步&quot;的分界线在阶段 2,&quot;阻塞/非阻塞&quot;的分界线在阶段 1——两组词描述两个不同的阶段,根本不该混用。</p><p>再澄清两个高频迷惑:</p><ul><li><strong>async/await 不等于异步 IO</strong>。它是语言层的写法糖,底下大概率是 epoll(Node、Python asyncio 都是)——语法看着异步,IO 模型是同步多路复用。</li><li><strong>Go 的网络读写&quot;看着阻塞&quot;,其实不阻塞线程</strong>。goroutine 里 <code>conn.Read()</code> 像阻塞调用,但 runtime 把 fd 设成了非阻塞,数据没到就把 goroutine 挂起、线程去跑别的 goroutine,netpoller(底层 epoll)就绪后再把它调回来。<strong>阻塞的是协程,不是线程</strong>——这是协程模型(17 篇)和 IO 模型在这里会师。</li></ul><hr><h2 id="八、reactor-与-proactor-模型之上的架构名字" tabindex="-1">八、Reactor 与 Proactor:模型之上的架构名字 <a class="header-anchor" href="#八、reactor-与-proactor-模型之上的架构名字" aria-label="Permalink to &quot;八、Reactor 与 Proactor:模型之上的架构名字&quot;">​</a></h2><p>工程里你更常听到的是这两个词,它们是事件驱动架构的两种形态,和上面的模型一一对应:</p><p><strong>Reactor</strong>(基于&quot;就绪&quot;通知):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>事件循环 epoll_wait 等&quot;谁就绪了&quot;</span></span>
<span class="line"><span>就绪 → 回调里自己 read/write</span></span></code></pre></div><p>epoll 体系的标准架构,Nginx、Redis、Node、Netty 都是 Reactor。</p><p><strong>Proactor</strong>(基于&quot;完成&quot;通知):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>提交操作 → 内核/运行时把活干完 → 回调里直接拿结果</span></span></code></pre></div><p>Windows 的 IOCP 是老牌 Proactor,io_uring 让 Linux 也有了像样的 Proactor 底座。</p><p>记法:<strong>Reactor 收到的是&quot;可以干活了&quot;,Proactor 收到的是&quot;活已经干完了&quot;</strong>。</p><hr><h2 id="九、选型-场景对答案" tabindex="-1">九、选型:场景对答案 <a class="header-anchor" href="#九、选型-场景对答案" aria-label="Permalink to &quot;九、选型:场景对答案&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>推荐</th><th>理由</th></tr></thead><tbody><tr><td>脚本、工具、几个连接</td><td>阻塞 IO</td><td>简单压倒一切,别过度设计</td></tr><tr><td>高并发网络服务</td><td>非阻塞 + epoll(Linux)/ kqueue(BSD/macOS)</td><td>久经考验的主流</td></tr><tr><td>文件 + 网络混合的高性能场景</td><td>io_uring</td><td>唯一两边都管的方案</td></tr><tr><td>写语言 runtime / 框架</td><td>封装 epoll/io_uring,对外暴露 async 或协程</td><td>把复杂度藏在 runtime 里</td></tr><tr><td>要等信号</td><td>signalfd 进事件循环</td><td>别碰裸 SIGIO</td></tr></tbody></table><p>还有一条容易踩的边界:<strong>普通磁盘文件的 fd 不适合放进 epoll</strong>——普通文件在 epoll 看来&quot;永远就绪&quot;(数据就在那,只是读起来慢),epoll 没法替你等磁盘 IO 完成。所以很多 runtime 是双轨制:网络走 epoll,文件 IO 丢线程池(或者上 io_uring 统一)。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>把 EAGAIN 当错误处理</strong>——它是非阻塞 IO 的正常状态,意思是&quot;暂时没有&quot;,直接报错断连是新手第一跤。</li><li><strong>&quot;epoll 是异步 IO&quot;</strong>——它是同步 IO 多路复用,只通知就绪,数据还得你自己 read;异步的定义是拷贝由内核完成。</li><li><strong>以为 epoll 会帮你把数据读好</strong>——epoll_wait 返回只代表&quot;可以读&quot;,不调 read 数据永远在内核缓冲区躺着。</li><li><strong>ET 模式不读到 EAGAIN 就收手</strong>——边缘触发只通知一次,剩下的数据没有下次通知,连接就此&quot;卡死&quot;(细节见 21 篇)。</li><li><strong>常驻监听 EPOLLOUT</strong>——socket 大部分时间都可写,事件循环会被写事件打满,CPU 100%;只在写不完时才注册它。</li><li><strong>在 async 函数 / 事件循环里调阻塞 IO</strong>——一个同步的数据库查询能把整个事件循环卡死,所有连接一起陪葬,这是 Node / asyncio 服务最经典的事故。</li><li><strong>拿普通文件 fd 喂 epoll</strong>——普通文件总是&quot;就绪&quot;,epoll 等不了磁盘;文件要么线程池,要么 io_uring。</li><li><strong>以为 async/await 在哪个语言里都是真异步 IO</strong>——多数是 epoll 套皮;判断标准只有一个:数据拷贝是谁做的。</li></ol><hr><p>下一篇:<code>21-epoll深入.md</code>,讲 epoll 内部的红黑树与就绪链表、LT/ET 两种触发模式的真实差别和 ET 三条铁律、EPOLLONESHOT 和 EPOLLEXCLUSIVE 各自解决什么、惊群问题怎么治,以及为什么 epoll 只是地基、生产级事件循环还要自己处理缓冲区和背压。</p>`,71)])])}const c=a(p,[["render",l]]);export{g as __pageData,c as default};
